     * Task: T020, T021, T022
     * Spec reference: FR-001, FR-008, FR-009, FR-011, FR-012, FR-013
     */
    @Get
    @Secured("ADMIN", "VULN")
    fun getOutdatedAssets(
        authentication: Authentication,
        @QueryValue(defaultValue = "") searchTerm: String?,
