        val hasRequiredRole = authentication.roles.any { it == "ADMIN" || it == "VULN" }
        if (!hasRequiredRole) {
            return HttpResponse.status(HttpStatus.FORBIDDEN)
        }

        val timestamp = outdatedAssetService.getLastRefreshTimestamp()

        return if (timestamp != null) {
