     * - 403 Forbidden: User lacks ADMIN or VULN role
     */
    @Get("/export")
    @Secured("ADMIN", "VULN")
    fun exportOutdatedAssets(
        authentication: Authentication,
        @QueryValue(defaultValue = "") searchTerm: String?,
        @QueryValue(defaultValue = "") minSeverity: String?,
